    26→        if (saved) {
    27→          setThemeModeState(saved as ThemeMode);
    28→        }
    29→        setIsLoaded(true);
    30→      })
    31→      .catch(() => setIsLoaded(true));
    32→  }, []);
    33→
    34→  const setThemeMode = async (mode: ThemeMode) => {
    35→    setThemeModeState(mode);
    36→    await AsyncStorage.setItem(THEME_KEY, mode);
    37→  };
