import React, { useState, useCallback, memo } from "react";
import {
  View,
  StyleSheet,
  FlatList,
  Pressable,
  Alert,
  TextInput,
} from "react-native";
import { useFocusEffect } from "@react-navigation/native";
import { useSafeAreaInsets } from "react-native-safe-area-context";
import { Feather } from "@expo/vector-icons";
import { ThemedText } from "@/components/ThemedText";
import { useTheme } from "@/hooks/useTheme";
import { useLanguage } from "@/hooks/useLanguage";
import { storage, User } from "@/utils/storage";
import { ScreenScrollView } from "@/components/ScreenScrollView";
import { Spacing, BorderRadius, Colors } from "@/constants/theme";

interface StatCardProps {
  label: string;
  value: number;
  color: string;
  theme: typeof Colors.light;
}

const StatCard = memo(({ label, value, color, theme }: StatCardProps) => (
  <View
    style={[
      styles.statCard,
      {
        backgroundColor: theme.backgroundDefault,
        borderColor: color + "30",
        borderWidth: 1,
      },
    ]}
  >
    <ThemedText type="small" style={{ color: theme.textSecondary }}>
      {label}
    </ThemedText>
    <ThemedText type="h2" style={{ color, marginTop: Spacing.xs }}>
      {value}
    </ThemedText>
  </View>
));

interface UserCardProps {
  user: User;
  theme: typeof Colors.light;
  t: any;
  onToggleActive: (user: User) => void;
  onDelete: (user: User) => void;
}

const UserCard = memo(({ user, theme, t, onToggleActive, onDelete }: UserCardProps) => (
  <View
    style={[
      styles.userCard,
      { backgroundColor: theme.backgroundDefault },
    ]}
  >
    <View style={styles.userInfo}>
      <View style={[styles.avatar, { backgroundColor: user.avatarColor }]}>
        <ThemedText type="h3" style={{ color: "#FFFFFF" }}>
          {user.name[0].toUpperCase()}
        </ThemedText>
      </View>
      <View style={{ flex: 1 }}>
        <ThemedText type="h3">{user.name}</ThemedText>
        <ThemedText type="small" style={{ color: theme.textSecondary }}>
          {user.email}
        </ThemedText>
        <View style={styles.userMeta}>
          <View
            style={[
              styles.badge,
              {
                backgroundColor: user.isActive
                  ? theme.presentGreen + "20"
                  : theme.error + "20",
              },
            ]}
          >
            <ThemedText
              type="small"
              style={{
                color: user.isActive ? theme.presentGreen : theme.error,
              }}
            >
              {user.isActive ? t.admin.active : t.admin.inactive}
            </ThemedText>
          </View>
          <View
            style={[styles.badge, { backgroundColor: theme.primary + "20" }]}
          >
            <ThemedText type="small" style={{ color: theme.primary }}>
              {user.role}
            </ThemedText>
          </View>
        </View>
      </View>
    </View>

    <View style={styles.actions}>
      <Pressable
        onPress={() => onToggleActive(user)}
        style={[
          styles.actionBtn,
          {
            backgroundColor: user.isActive
              ? theme.error + "15"
              : theme.presentGreen + "15",
          },
        ]}
      >
        <Feather
          name={user.isActive ? "lock" : "unlock"}
          size={18}
          color={user.isActive ? theme.error : theme.presentGreen}
        />
      </Pressable>
      <Pressable
        onPress={() => onDelete(user)}
        style={[styles.actionBtn, { backgroundColor: theme.error + "15" }]}
      >
        <Feather name="trash-2" size={18} color={theme.error} />
      </Pressable>
    </View>
  </View>
));

export default function AdminDashboardScreen() {
  const { theme } = useTheme();
  const { t } = useLanguage();
  const insets = useSafeAreaInsets();
  const tabBarHeight = insets.bottom + 60;

  const [users, setUsers] = useState<User[]>([]);
  const [filteredUsers, setFilteredUsers] = useState<User[]>([]);
  const [searchQuery, setSearchQuery] = useState("");
  const [stats, setStats] = useState({
    total: 0,
    active: 0,
    inactive: 0,
    loggedIn: 0,
  });

  useFocusEffect(
    useCallback(() => {
      loadUsers();
    }, [])
  );

  const loadUsers = async () => {
    const loadedUsers = await storage.getUsers();
    setUsers(loadedUsers);
    setFilteredUsers(loadedUsers);
    updateStats(loadedUsers);
  };

  const updateStats = (userList: User[]) => {
    setStats({
      total: userList.length,
      active: userList.filter((u) => u.isActive).length,
      inactive: userList.filter((u) => !u.isActive).length,
      loggedIn: userList.filter(
        (u) => u.loginHistory && u.loginHistory.length > 0
      ).length,
    });
  };

  const handleSearch = (query: string) => {
    setSearchQuery(query);
    const filtered = users.filter(
      (u) =>
        u.name.toLowerCase().includes(query.toLowerCase()) ||
        u.email.toLowerCase().includes(query.toLowerCase())
    );
    setFilteredUsers(filtered);
  };

  const handleToggleActive = async (user: User) => {
    const updated = { ...user, isActive: !user.isActive };
    await storage.updateUser(updated);
    await loadUsers();
  };

  const handleDeleteUser = (user: User) => {
    Alert.alert(t.admin.deleteUser, `${t.common.delete} ${user.name}?`, [
      { text: t.common.cancel, style: "cancel" },
      {
        text: t.admin.deleteConfirm,
        style: "destructive",
        onPress: async () => {
          await storage.deleteUser(user.id);
          await loadUsers();
        },
      },
    ]);
  };

  const renderUser = ({ item }: { item: User }) => (
    <UserCard
      user={item}
      theme={theme}
      t={t}
      onToggleActive={handleToggleActive}
      onDelete={handleDeleteUser}
    />
  );

  return (
    <ScreenScrollView
      contentContainerStyle={{
        paddingBottom: tabBarHeight + Spacing.xl,
      }}
    >
      <ThemedText type="h1" style={{ marginBottom: Spacing.lg }}>
        {t.admin.dashboard}
      </ThemedText>

      <View style={styles.statsContainer}>
        <StatCard
          label={t.admin.totalUsers}
          value={stats.total}
          color={theme.primary}
          theme={theme}
        />
        <StatCard
          label={t.admin.active}
          value={stats.active}
          color={theme.presentGreen}
          theme={theme}
        />
        <StatCard
          label={t.admin.inactive}
          value={stats.inactive}
          color={theme.error}
          theme={theme}
        />
      </View>

      <View style={styles.statsContainer}>
        <StatCard
          label={t.admin.loggedIn}
          value={stats.loggedIn}
          color={theme.primary}
          theme={theme}
        />
      </View>

      <View
        style={[
          styles.searchBox,
          {
            backgroundColor: theme.backgroundDefault,
            borderColor: theme.border,
          },
        ]}
      >
        <Feather name="search" size={20} color={theme.textSecondary} />
        <TextInput
          style={[styles.searchInput, { color: theme.text }]}
          placeholder={t.admin.searchUsers}
          placeholderTextColor={theme.textSecondary}
          value={searchQuery}
          onChangeText={handleSearch}
        />
      </View>

      <ThemedText
        type="h3"
        style={[styles.sectionTitle, { color: theme.textSecondary }]}
      >
        {t.admin.users} ({filteredUsers.length})
      </ThemedText>

      <FlatList
        data={filteredUsers}
        keyExtractor={(item) => item.id}
        renderItem={renderUser}
        scrollEnabled={false}
        ItemSeparatorComponent={() => <View style={{ height: Spacing.md }} />}
        ListEmptyComponent={
          <ThemedText
            type="body"
            style={{
              textAlign: "center",
              marginTop: Spacing.xl,
              color: theme.textSecondary,
            }}
          >
            {t.admin.noUsersFound}
          </ThemedText>
        }
      />
    </ScreenScrollView>
  );
}

