import React, { useState, useEffect, useLayoutEffect } from "react";
import {
  View,
  StyleSheet,
  TextInput,
  Pressable,
  Alert,
  Image,
  Platform,
  Linking,
} from "react-native";
import { useNavigation, useRoute, RouteProp } from "@react-navigation/native";
import { NativeStackNavigationProp } from "@react-navigation/native-stack";
import { Feather } from "@expo/vector-icons";
import Animated, {
  useAnimatedStyle,
  useSharedValue,
  withSpring,
} from "react-native-reanimated";
import * as Haptics from "expo-haptics";
import * as ImagePicker from "expo-image-picker";
import { ThemedText } from "@/components/ThemedText";
import { ThemedView } from "@/components/ThemedView";
import { useTheme } from "@/hooks/useTheme";
import { useLanguage } from "@/hooks/useLanguage";
import {
  storage,
  Worker,
  WorkerCategory,
  generateId,
} from "@/utils/storage";
import { Spacing, BorderRadius } from "@/constants/theme";
import { RootStackParamList } from "@/navigation/MainTabNavigator";
import { ScreenKeyboardAwareScrollView } from "@/components/ScreenKeyboardAwareScrollView";

const CATEGORIES: WorkerCategory[] = [
  "labour",
  "bai",
  "mistri",
  "bandkam",
  "plaster",
  "tiles",
  "sutar",
];

const AnimatedPressable = Animated.createAnimatedComponent(Pressable);

function SectionHeader({ title }: { title: string }) {
  const { theme } = useTheme();
  return (
    <ThemedText
      type="small"
      style={{ color: theme.textSecondary, textTransform: "uppercase", letterSpacing: 0.8, marginBottom: Spacing.sm, marginTop: Spacing.lg }}
    >
      {title}
    </ThemedText>
  );
}

export default function AddWorkerScreen() {
  const { theme } = useTheme();
  const { t } = useLanguage();
  const navigation =
    useNavigation<NativeStackNavigationProp<RootStackParamList>>();
  const route = useRoute<RouteProp<RootStackParamList, "AddWorker">>();

  const workerId = route.params?.workerId;
  const isEditing = !!workerId;

  const [name, setName] = useState("");
  const [category, setCategory] = useState<WorkerCategory>("labour");
  const [dailyRate, setDailyRate] = useState("");
  const [phone, setPhone] = useState("");
  const [address, setAddress] = useState("");
  const [notes, setNotes] = useState("");
  const [photoUri, setPhotoUri] = useState<string | undefined>(undefined);
  const [isLoading, setIsLoading] = useState(false);

  const saveButtonScale = useSharedValue(1);

  const animatedSaveStyle = useAnimatedStyle(() => ({
    transform: [{ scale: saveButtonScale.value }],
  }));

  useEffect(() => {
    if (workerId) {
      loadWorker();
    }
  }, [workerId]);

  useLayoutEffect(() => {
    navigation.setOptions({
      headerTitle: isEditing ? t.workers.editWorker : t.workers.addWorker,
      headerLeft: () => (
        <Pressable onPress={() => navigation.goBack()} style={styles.headerButton}>
          <ThemedText style={{ color: theme.primary }}>
            {t.common.cancel}
          </ThemedText>
        </Pressable>
      ),
      headerRight: () => (
        <Pressable onPress={handleSave} style={styles.headerButton}>
          <ThemedText style={{ color: theme.primary, fontWeight: "600" }}>
            {t.common.save}
          </ThemedText>
        </Pressable>
      ),
    });
  }, [navigation, name, category, dailyRate, phone, address, notes, photoUri, isEditing]);

  const loadWorker = async () => {
    const workers = await storage.getWorkers();
    const worker = workers.find((w) => w.id === workerId);
    if (worker) {
      setName(worker.name);
      setCategory(worker.category);
      setDailyRate(worker.dailyRate.toString());
      setPhone(worker.phone || "");
      setAddress(worker.address || "");
      setNotes(worker.notes || "");
      setPhotoUri(worker.photoUri);
    }
  };

  const handlePickPhoto = () => {
    Alert.alert(
      t.workers.addPhoto,
      "",
      [
        {
          text: "Camera",
          onPress: pickFromCamera,
        },
        {
          text: "Gallery",
          onPress: pickFromGallery,
        },
        { text: t.common.cancel, style: "cancel" },
      ]
    );
  };

  const pickFromCamera = async () => {
    const { status } = await ImagePicker.requestCameraPermissionsAsync();
    if (status !== "granted") {
      Alert.alert(t.common.error, "Camera permission denied");
      return;
    }
    const result = await ImagePicker.launchCameraAsync({
      mediaTypes: "images",
      allowsEditing: true,
      aspect: [1, 1],
      quality: 0.7,
    });
    if (!result.canceled && result.assets[0]) {
      setPhotoUri(result.assets[0].uri);
    }
  };

  const pickFromGallery = async () => {
    const { status } = await ImagePicker.requestMediaLibraryPermissionsAsync();
    if (status !== "granted") {
      Alert.alert(t.common.error, "Gallery permission denied");
      return;
    }
    const result = await ImagePicker.launchImageLibraryAsync({
      mediaTypes: "images",
      allowsEditing: true,
      aspect: [1, 1],
      quality: 0.7,
    });
    if (!result.canceled && result.assets[0]) {
      setPhotoUri(result.assets[0].uri);
    }
  };

  const handleSave = async () => {
    if (!name.trim()) {
      Alert.alert(t.common.error, t.workers.enterName);
      return;
    }

    const rate = parseFloat(dailyRate);
    if (isNaN(rate) || rate <= 0) {
      Alert.alert(t.common.error, t.workers.enterRate);
      return;
    }

    setIsLoading(true);

    try {
      if (isEditing && workerId) {
        const workers = await storage.getWorkers();
        const existingWorker = workers.find((w) => w.id === workerId);
        if (existingWorker) {
          const updatedWorker: Worker = {
            ...existingWorker,
            name: name.trim(),
            category,
            dailyRate: rate,
            phone: phone.trim() || undefined,
            address: address.trim() || undefined,
            notes: notes.trim() || undefined,
            photoUri: photoUri,
          };
          await storage.updateWorker(updatedWorker);
        }
      } else {
        const newWorker: Worker = {
          id: generateId(),
          name: name.trim(),
          category,
          dailyRate: rate,
          phone: phone.trim() || undefined,
          address: address.trim() || undefined,
          notes: notes.trim() || undefined,
          photoUri: photoUri,
          createdAt: Date.now(),
        };
        await storage.addWorker(newWorker);
      }

      Haptics.notificationAsync(Haptics.NotificationFeedbackType.Success);
      navigation.goBack();
    } catch (error) {
      Alert.alert(t.common.error, t.workers.saveFailed);
    } finally {
      setIsLoading(false);
    }
  };

  const getCategoryColor = (cat: WorkerCategory) => {
    const colors: Record<WorkerCategory, string> = {
      labour: "#4CAF50",
      bai: "#E91E63",
      mistri: "#1E3A5F",
      bandkam: "#795548",
      plaster: "#9C27B0",
      tiles: "#00BCD4",
      sutar: "#FF9800",
    };
    return colors[cat] || "#FF6B35";
  };

  const initials = name.trim()
    ? name.trim().split(" ").map((w) => w[0]).join("").toUpperCase().slice(0, 2)
    : "?";

  return (
    <ThemedView style={styles.container}>
      <ScreenKeyboardAwareScrollView contentContainerStyle={styles.scrollContent}>

        {/* Photo Avatar */}
        <View style={styles.avatarSection}>
          <Pressable onPress={handlePickPhoto} style={styles.avatarWrapper}>
            {photoUri ? (
              <Image source={{ uri: photoUri }} style={styles.avatar} />
            ) : (
              <View style={[styles.avatarPlaceholder, { backgroundColor: getCategoryColor(category) }]}>
                <ThemedText style={styles.avatarInitials}>{initials}</ThemedText>
              </View>
            )}
            <View style={[styles.cameraIcon, { backgroundColor: theme.primary }]}>
              <Feather name="camera" size={14} color="#FFFFFF" />
            </View>
          </Pressable>
          <ThemedText type="small" style={{ color: theme.textSecondary, marginTop: Spacing.sm }}>
            {photoUri ? t.workers.changePhoto : t.workers.addPhoto}
          </ThemedText>
        </View>

        {/* Basic Info */}
        <View style={styles.formGroup}>
          <ThemedText type="h4" style={styles.label}>
            {t.workers.name}
          </ThemedText>
          <TextInput
            style={[styles.input, { color: theme.text, backgroundColor: theme.backgroundDefault, borderColor: theme.border }]}
            value={name}
            onChangeText={setName}
            placeholder={t.workers.name}
            placeholderTextColor={theme.textSecondary}
            autoFocus={!isEditing}
          />
        </View>

        {/* Category */}
        <View style={styles.formGroup}>
          <ThemedText type="h4" style={styles.label}>
            {t.workers.category}
          </ThemedText>
          <View style={styles.categoryGrid}>
            {CATEGORIES.map((cat) => (
              <Pressable
                key={cat}
                onPress={() => {
                  Haptics.impactAsync(Haptics.ImpactFeedbackStyle.Light);
                  setCategory(cat);
                }}
                style={[
                  styles.categoryItem,
                  {
                    backgroundColor: category === cat ? getCategoryColor(cat) : theme.backgroundDefault,
                    borderColor: category === cat ? getCategoryColor(cat) : theme.border,
                  },
                ]}
              >
                <ThemedText
                  type="small"
                  style={{
                    color: category === cat ? "#FFFFFF" : theme.text,
                    fontWeight: category === cat ? "600" : "400",
                  }}
                >
                  {t.categories[cat]}
                </ThemedText>
              </Pressable>
            ))}
          </View>
        </View>

        {/* Daily Rate */}
        <View style={styles.formGroup}>
          <ThemedText type="h4" style={styles.label}>
            {t.workers.dailyRate} ({t.common.currency})
          </ThemedText>
          <TextInput
            style={[styles.input, { color: theme.text, backgroundColor: theme.backgroundDefault, borderColor: theme.border }]}
            value={dailyRate}
            onChangeText={setDailyRate}
            placeholder="500"
            placeholderTextColor={theme.textSecondary}
            keyboardType="numeric"
          />
        </View>

        {/* Contact Info */}
        <SectionHeader title={t.workers.contactInfo} />
        <View style={[styles.card, { backgroundColor: theme.backgroundDefault, borderColor: theme.border }]}>
          <View style={styles.cardRow}>
            <Feather name="phone" size={18} color={theme.textSecondary} style={styles.rowIcon} />
            <TextInput
              style={[styles.cardInput, { color: theme.text }]}
              value={phone}
              onChangeText={setPhone}
              placeholder={`${t.workers.phone} (${t.workers.optional})`}
              placeholderTextColor={theme.textSecondary}
              keyboardType="phone-pad"
            />
          </View>
          <View style={[styles.cardDivider, { backgroundColor: theme.border }]} />
          <View style={styles.cardRow}>
            <Feather name="map-pin" size={18} color={theme.textSecondary} style={styles.rowIcon} />
            <TextInput
              style={[styles.cardInput, { color: theme.text }]}
              value={address}
              onChangeText={setAddress}
              placeholder={`${t.workers.address} (${t.workers.optional})`}
              placeholderTextColor={theme.textSecondary}
            />
          </View>
        </View>

        {/* Notes */}
        <SectionHeader title={t.workers.additionalInfo} />
        <View style={[styles.card, { backgroundColor: theme.backgroundDefault, borderColor: theme.border }]}>
          <TextInput
            style={[styles.notesInput, { color: theme.text }]}
            value={notes}
            onChangeText={setNotes}
            placeholder={t.workers.notesPlaceholder}
            placeholderTextColor={theme.textSecondary}
            multiline
            numberOfLines={3}
            textAlignVertical="top"
          />
        </View>

        {/* Save Button */}
        <AnimatedPressable
          onPress={handleSave}
          onPressIn={() => { saveButtonScale.value = withSpring(0.96); }}
          onPressOut={() => { saveButtonScale.value = withSpring(1); }}
          disabled={isLoading}
          style={[styles.saveButton, { backgroundColor: theme.primary, opacity: isLoading ? 0.6 : 1 }, animatedSaveStyle]}
        >
          <ThemedText style={styles.saveButtonText}>
            {isLoading ? t.common.loading : t.common.save}
          </ThemedText>
        </AnimatedPressable>
      </ScreenKeyboardAwareScrollView>
    </ThemedView>
  );
