   412→export function getDaysInMonth(year: number, month: number): number {
   413→  return new Date(year, month + 1, 0).getDate();
   414→}
   415→
   416→export function calculateWorkerSummary(
   417→  workerId: string,
   418→  attendance: AttendanceRecord[],
   419→  dailyRate: number
   420→): {
   421→  presentDays: number;
   422→  halfDays: number;
   423→  absentDays: number;
   424→  totalAmount: number;
   425→} {
   426→  const workerAttendance = attendance.filter((a) => a.workerId === workerId);
   427→
   428→  let presentDays = 0;
   429→  let halfDays = 0;
   430→  let absentDays = 0;
   431→  let customAmount = 0;
   432→
   433→  workerAttendance.forEach((record) => {
   434→    if (record.value === "P") {
   435→      presentDays++;
   436→    } else if (record.value === "A") {
   437→      absentDays++;
   438→    } else if (record.value === "H") {
   439→      halfDays++;
   440→    } else if (typeof record.value === "number") {
   441→      customAmount += record.value;
   442→    }
   443→  });
   444→
   445→  const totalAmount =
   446→    presentDays * dailyRate + halfDays * (dailyRate / 2) + customAmount;
   447→
   448→  return { presentDays, halfDays, absentDays, totalAmount };
   449→}
