          a.workerId === worker.id &&
          a.year === year &&
          a.month === month &&
          a.day === i + 1
      );
      const value = record?.value ?? null;
      const bgColor = getAttendanceCellColor(value);
      const textColor = getAttendanceTextColor(value);
